+// ============================================================================
+// JSONL log entry
+// ============================================================================
+
+#[derive(Debug, serde::Serialize)]
+struct LogEntry {
+    event: &'static str,
+    operation: &'static str,
+    step: u32,
+    snapshot_count: u32,
+    state_hash: String,
+    expected_hash: String,
+    #[serde(rename = "match")]
+    is_match: bool,
+    op_time_ns: u64,
+}
+
+fn hash_state<T: Hash>(state: &T) -> String {
+    let mut hasher = DefaultHasher::new();
+    state.hash(&mut hasher);
+    format!("{:016x}", hasher.finish())
+}
